diff --git a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
index a88f8f19f852..b292cd6a2381 100644
--- a/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
+++ b/llvm/lib/Transforms/Scalar/SeparateConstOffsetFromGEP.cpp
@@ -839,7 +839,7 @@ static bool allowsPreservingNUW(const User *U) {
   // is distributed through an add nuw, wrapping may occur:
   // "add nuw trunc(a), trunc(b)" is more poisonous than "trunc(add nuw a, b)"
   if (const TruncInst *TI = dyn_cast<TruncInst>(U))
-    return TI->hasNoUnsignedWrap();
+    return TI->hasNoUnsignedWrap() && TI->hasNoSignedWrap();
   return isa<CastInst>(U) || isa<ConstantInt>(U);
 }

@@ -858,6 +858,27 @@ Value *ConstantOffsetExtractor::Extract(Value *Idx, GetElementPtrInst *GEP,
   }

   PreservesNUW = all_of(Extractor.UserChain, allowsPreservingNUW);
+  for (User *U : Extractor.UserChain) {
+    if (isa<TruncInst>(U)) {
+      UserChainTail = nullptr;
+      return nullptr;
+    }
+  }
+  for (User *U : Extractor.UserChain) {
+    if (auto *TI = dyn_cast<TruncInst>(U)) {
+      if (TI->hasNoSignedWrap()) { PreservesNUW = false; break; }
+    }
+  }
+  if (GEP->hasNoUnsignedWrap() && !PreservesNUW) {
+    UserChainTail = nullptr;
+    return nullptr;
+  }
+  // Do not reassociate through trunc with NSW, as it can strengthen poison.
+  for (User *U : Extractor.UserChain) {
+    if (auto *TI = dyn_cast<TruncInst>(U)) {
+      if (TI->hasNoSignedWrap()) { PreservesNUW = false; break; }
+    }
+  }

   // Separates the constant offset from the GEP index.
   Value *IdxWithoutConstOffset = Extractor.rebuildWithoutConstOffset();
@@ -1055,6 +1076,21 @@ bool SeparateConstOffsetFromGEP::splitGEP(GetElementPtrInst *GEP) {
   if (GEP->hasAllConstantIndices() && !ExtractBase)
     return false;

+  // Bail out if any sequential index is a trunc, to avoid changing poison behavior.
+  gep_type_iterator PreGTI = gep_type_begin(*GEP);
+  for (unsigned PI = 1, PE = GEP->getNumOperands(); PI != PE; ++PI, ++PreGTI) {
+    if (!PreGTI.isSequential()) continue;
+    if (isa<TruncInst>(GEP->getOperand(PI))) return false;
+  }
+//  // Conservatively bail out if any sequential index is a trunc with NSW, to avoid strengthening poison when distributing additions across trunc.
+//gep_type_iterator PreGTI = gep_type_begin(*GEP);
+//for (unsigned PI = 1, PE = GEP->getNumOperands(); PI != PE; ++PI, ++PreGTI) {
+//  if (!PreGTI.isSequential()) continue;
+//  if (auto *TI = dyn_cast<TruncInst>(GEP->getOperand(PI))) {
+//    if (TI->hasNoSignedWrap()) return false; /* Do not transform */
+//  }
+//}
+//
   bool Changed = canonicalizeArrayIndicesToIndexSize(GEP);

   bool NeedsExtraction;
@@ -1119,7 +1155,7 @@ bool SeparateConstOffsetFromGEP::splitGEP(GetElementPtrInst *GEP) {
         // and the old index if they are not used.
         RecursivelyDeleteTriviallyDeadInstructions(UserChainTail);
         RecursivelyDeleteTriviallyDeadInstructions(OldIdx);
-        AllOffsetsNonNegative =
+        AccumulativeByteOffset += 0; AllOffsetsNonNegative =
             AllOffsetsNonNegative && isKnownNonNegative(NewIdx, *DL);
         AllNUWPreserved &= PreservesNUW;
       }

